export const fpActivities: Activity[] = [
  {"id":"fp-sponge-stamp-printing","title":"Sponge Stamp Printing","altNames":["Sponge Stamps","Sponge Print Art","Foam Sponge Stamping"],"type":"Craft","place":"Inside","ageMin":6,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Cut your own sponge stamps and press bold repeating shapes into a one-of-a-kind print.","materials":["Sponges, 1-2 per camper","Scissors","Paint in shallow trays/paper plates","Assorted paper, 1-2 sheets per camper","Markers for outlining (optional)","Paper towels for cleanup","Masking tape (to anchor paper)"],"materialTags":["Sponges","Scissors","Paint","Paper","Markers","Paper towels","Masking tape"],"steps":["Draw a simple shape (star, leaf, heart, fish) onto a dry sponge with marker.","Cut the sponge along the marker line to create a stamp; squeeze and dampen it slightly so it grips paint.","Pour a thin layer of paint onto a paper plate and press the sponge stamp lightly into it.","Tape a sheet of paper down, then press the loaded stamp firmly onto the paper and lift straight up without smearing.","Reload between prints and repeat the shape in a pattern across the page.","Let prints dry flat, then add marker details or outlines once the paint sets."],"notes":"Seat campers in pairs sharing a paint tray to cut down on mess and reloading lines. Remind them less paint gives a crisper print; the first stamp of each reload is usually best. For g79 scale up by having them design a multi-color repeating pattern or a layered two-stamp scene.","safety":"Scissors cut wet sponges awkwardly and can slip toward fingers; have campers cut sponges DRY and keep the non-cutting hand clear of the blade path.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"How to make sponge STAMPS for kids — DIY sponge painting video","url":"https://www.youtube.com/watch?v=Vs5ivoqLgGY"}],"links":[{"label":"Little Bins for Little Hands: summer camp art activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Cut several small sponge shapes and combine them into a scene like a garden or underwater reef.","Use only one color but vary the pressure to create light and dark print tones.","Younger campers can use pre-cut geometric sponge pieces instead of cutting their own shapes.","For g79, challenge campers to print a repeating tessellation where stamped shapes interlock edge-to-edge with no gaps."],"subsets":[["Pick a simple bold shape with no thin parts","Draw it large enough to cut cleanly"],[],["A thin layer, not a puddle","Blot extra paint on a paper towel"],["Press straight down, do not rock the stamp","Lift in one clean motion"],[],[]]},
  {"id":"fp-bubble-wrap-printing","title":"Bubble Wrap Printing","altNames":["Bubble Wrap Stamps","Bubble Print Art","Pop Print Painting"],"type":"Craft","place":"Inside","ageMin":6,"ageMax":12,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Roll paint onto bubble wrap and press it down for an instant polka-dot texture print.","materials":["Bubble wrap, palm-sized pieces, 1 per camper","Paint in shallow trays","Paintbrushes or sponges, 1 per camper","Assorted paper, 1-2 sheets per camper","Masking tape","Paper towels"],"materialTags":["Paint","Paintbrushes","Paper","Masking tape","Sponges","Paper towels"],"steps":["Tape a sheet of paper flat to the table so it cannot slide.","Brush or sponge a thin layer of paint over the bumpy side of a bubble wrap piece.","Flip the painted bubble wrap onto the paper and press evenly across the whole surface with a flat hand.","Peel the bubble wrap straight up to reveal the dotted texture print.","Re-ink and overlap a second color in another corner for a layered effect.","Set the print aside to dry and reuse the bubble wrap by wiping it on a paper towel."],"notes":"This is a fast, low-frustration print that works well as a background other crafts can be glued onto. Keep paint thin or the bubbles fill in and lose their pattern. Pair campers so one presses while the other holds the paper edge.","safety":"Paint-coated bubble wrap is slippery; warn campers not to walk on dropped pieces, which can cause a slip on hard floors.","ages":["g13","g46"],"rating":0,"media":[{"title":"Bubble Wrap Painting — bubble wrap printing technique video (Part 1)","url":"https://www.youtube.com/watch?v=9pxX7-NHYfg"}],"links":[{"label":"Little Bins for Little Hands: summer camp art activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Print onto a fish or jellyfish shape pre-cut from paper for an under-the-sea look.","Use a rainbow of colors brushed side by side on one bubble wrap piece for a gradient print.","Turn the prints into wrapping paper or card fronts for a kindness-theme gift.","Cut bubble wrap into letter shapes so older campers can print their name or a word in dotted texture."],"subsets":[[],["Coat the bumpy side, not the flat side","Thin coat keeps dots crisp"],["Press evenly so edges print too"],[],[],[]]},
  {"id":"fp-shaving-cream-marbling","title":"Shaving Cream Marbling","altNames":["Foam Marbling","Marbled Paper","Shaving Foam Swirl Art"],"type":"Craft","place":"Inside","ageMin":9,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Swirl drops of paint across a foam tray, press paper down, and scrape away a marbled masterpiece.","materials":["Shaving cream (foam), 1 can per table","Paint, a few colors per table","Assorted paper or cardstock, 2 sheets per camper","Cardboard scrap or straw for swirling, 1 per camper","Clothespins or a ruler edge for scraping","Paper towels","Paper plates or trays"],"materialTags":["Paint","Paper","Cardboard","Straws","Clothespins","Paper towels"],"steps":["Spray a flat layer of shaving foam onto a paper plate or tray and smooth the top.","Drip several small dots of different paint colors across the foam surface.","Drag a straw or cardboard edge through the dots in swirls and figure-eights to marble the colors.","Press a sheet of paper gently onto the foam and pat so it makes full contact.","Lift the paper straight up; the foam will come with it carrying the pattern.","Scrape the foam off the paper with a clothespin or ruler edge to reveal the crisp marbled print underneath.","Lay the print flat to dry while the foam tray gets re-swirled for the next print."],"notes":"The reveal when you scrape the foam off is the payoff, so save it as a group countdown moment. One foam tray can make three or four prints before colors muddy. For g79, have them plan a two-pull print, marbling, pulling, re-marbling, and pulling a second layer for depth.","safety":"Shaving foam stings badly in eyes; keep cans pointed down and away from faces, and have campers wash hands before touching their face.","ages":["g46","g79"],"rating":0,"media":[{"title":"How to Marble Paper with Shaving Cream — easy DIY for kids (video tutorial)","url":"https://www.youtube.com/watch?v=B_goYNaxzf4"}],"links":[{"label":"Little Bins for Little Hands: summer camp art activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Marble onto cardstock bookmarks and trim them down once dry.","Use only two colors that mix into a third (blue and yellow) so campers see color blending in the swirls.","Marble onto pre-folded card blanks to make greeting cards.","For g1012, challenge them to control the marble into a deliberate target pattern like a galaxy or a feather rather than random swirls."],"subsets":[["Flat even layer, not a mound","Smooth the top with a cardboard edge"],[],["Swirl gently, do not overmix or it turns gray"],[],[],["Scrape with one firm pull","Wipe the scraper between prints"],[]]},
  {"id":"fp-splatter-pollock-art","title":"Splatter (Pollock) Action Art","altNames":["Pollock Splatter Art","Flick Painting","Drip and Splatter Art"],"type":"Craft","place":"Outside","ageMin":6,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":2,"prep":"Medium","blurb":"Flick, drip, and fling watered-down paint Jackson-Pollock style for an explosive splatter canvas.","materials":["Paint thinned with water in cups","Paintbrushes, 1-2 per camper","Large assorted paper or cardboard, 1 per camper","Straws for blowing drips (optional)","Drop cloth or extra cardboard to protect ground","Masking tape","Paper towels"],"materialTags":["Paint","Paintbrushes","Paper","Cardboard","Straws","Masking tape","Paper towels"],"steps":["Set up outside on grass or a tarp and tape paper or cardboard flat on the ground.","Thin paint with a little water in cups so it drips and flings off the brush.","Load a brush, hold it over the paper, and flick the wrist to splatter dots across the surface.","Switch colors and vary the motion, snapping for fine speckles and slinging for big drops.","Dribble a loaded brush slowly across the paper to lay down trailing lines between splatters.","Step back, let it dry, and name the finished piece together."],"notes":"Do this outdoors only and stagger campers so flying paint does not cross onto a neighbor's clothes. Thin paint splatters far better than thick. For g1012, assign a limited palette and a composition goal (balance, movement) so it reads as deliberate action art rather than random mess.","safety":"Flung paint travels and stains; require campers to keep an arm's-length spacing facing the same direction and to wear smocks or old shirts, never aiming a loaded brush toward anyone.","ages":["g13","g46","g79","g1012"],"rating":0,"links":[{"label":"Little Bins for Little Hands: summer camp art activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Lay a paper cutout (star, initial) on the page, splatter around it, then lift it to leave a clean silhouette.","Use glow or single-color splatter on black paper for a night-sky effect.","Make a group mural by having the whole cabin splatter onto one giant sheet of cardboard.","For g79, give each camper one color and have them layer splatters in turns to build a coordinated palette across the same canvas."],"subsets":[["Tape edges so wind does not lift the paper"],["Add water a little at a time until it drips off the brush"],["Practice a test flick off to the side first","Aim down, never sideways at people"],[],[],[]]},
  {"id":"fp-straw-blow-painting","title":"Straw Blow Painting","altNames":["Blow Painting","Straw Paint Art","Blown Ink Art"],"type":"Craft","place":"Inside","ageMin":6,"ageMax":15,"durationMin":30,"groupMin":null,"groupMax":null,"energy":2,"prep":"Low","blurb":"Drop a blob of thinned paint and blow it through a straw into wild branching tendrils.","materials":["Straws, 1 per camper","Paint thinned with water in cups","Spoons or pipettes for dropping paint","Assorted paper or cardstock, 1-2 per camper","Masking tape","Paper towels"],"materialTags":["Straws","Paint","Paper","Masking tape","Paper towels"],"steps":["Thin paint with water in cups until it is runny enough to move when blown.","Spoon or drop a small blob of paint onto the paper.","Hold a straw just above (not touching) the blob and blow hard to push the paint outward into branches.","Turn the paper or blow from different angles to grow the tendrils in new directions.","Add a second color blob and blow it to overlap and tangle with the first.","Let the paper dry flat and add marker details like petals or insects on the branch tips."],"notes":"Best as a focused tabletop activity; remind campers to BLOW not suck so they do not get a mouthful of paint. Thin paint moves; thick paint just sits there. For g79, turn it into a planned tree, coral, or lightning composition where they steer the branches deliberately.","safety":"Campers must only blow, never inhale, through the straw; give each camper their own straw and tell them not to share to keep it sanitary.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Easy Blow Painting with Straws — kids art technique (video tutorial)","url":"https://www.youtube.com/watch?v=T0mVJTxL3go"}],"links":[{"label":"Little Bins for Little Hands: summer camp art activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Blow paint up from the bottom of the page to make a spooky bare tree, then add fingerprint leaves.","Use warm colors blown outward from a center to make a firework or dandelion burst.","Bend a flexible straw to control low-angle blowing for finer branches.","For g1012, have them render a deliberate subject such as a nervous-system or river-delta diagram, steering branches to a planned map."],"subsets":[["Runny but not watery"],["Small blob; you can always add more"],["Keep the straw tip off the paint","Short hard puffs steer better than one long blow"],[],[],[]]},
  {"id":"fp-ice-cube-painting","title":"Ice Cube Painting","altNames":["Frozen Paint Painting","Ice Paint Pops","Melting Color Art"],"type":"Craft","place":"Both","ageMin":6,"ageMax":12,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"High","blurb":"Paint with frozen color cubes that melt into dreamy, blending washes as you draw.","materials":["Ice cubes frozen with a little paint or watercolor, 2-3 per camper","Craft sticks or straws frozen in as handles (optional)","Assorted paper or cardstock, 1-2 per camper","Paper towels","Tray or paper plates to catch melt"],"materialTags":["Paint","Paper","Straws","Paper towels","Water source"],"steps":["The day before, freeze ice cube trays filled with water tinted by a squeeze of paint, standing a straw in each for a handle.","Hand each camper a few colored ice cubes on a tray or plate to catch drips.","Drag a melting cube across the paper like a crayon to lay down a wash of color.","Press and hold the cube in spots to let it puddle and bleed into soft blooms.","Layer a second color over the first while both are wet to watch them blend.","Set the painting flat to dry; the colors keep shifting as the last melt soaks in."],"notes":"Prep is front-loaded: freeze cubes the night before and keep them in a cooler until use. Great on a hot day since the cubes are refreshingly cold to hold. For older campers, pair it with a color-mixing lesson on which overlaps make secondary colors.","safety":"Melt water makes tables and floors slick; keep a tray under each camper and wipe drips so no one slips, and remind campers not to put colored ice in their mouths.","ages":["g13","g46"],"rating":0,"links":[{"label":"Little Bins for Little Hands: summer camp art activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Freeze each cube a single bold color so campers can collect a full rainbow set.","Paint on thick cardstock so the heavy melt does not tear thinner paper.","Use the cubes outside on the sidewalk for a cool-down chalk-style color session.","Older campers can predict and chart which two colors will blend into which before painting to test it."],"subsets":[["Add only a little paint so cubes freeze solid","Stand a straw in each before freezing"],[],[],["Hold still to bloom, drag to streak"],[],[]]},
  {"id":"fp-water-pistol-spray-painting","title":"Water Pistol Spray Painting","altNames":["Squirt Gun Painting","Spray Bottle Art","Water Blaster Painting"],"type":"Craft","place":"Outside","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":3,"prep":"Medium","blurb":"Load thinned paint into spray bottles and blast a big drippy painting from across the lawn.","materials":["Spray bottles or squirt bottles filled with thinned paint, 1 per color","Paint thinned heavily with water","Large assorted paper or cardboard taped to a fence, 1 per camper","Masking tape","Water source for filling and rinsing","Paper towels"],"materialTags":["Paint","Paper","Cardboard","Masking tape","Water source","Paper towels"],"steps":["Tape large paper or cardboard to a fence or wall outdoors, away from anything you do not want sprayed.","Fill spray or squirt bottles with paint thinned heavily with water so it sprays freely.","Stand a few feet back and spray a color across the paper, letting it run and drip.","Switch colors and aim into different zones, mixing where the sprays overlap.","Move closer for concentrated spots and farther for a fine misted spread.","Let the painting drip and dry on the fence before peeling it down."],"notes":"Strictly an outdoor activity with paper anchored to a vertical surface so drips run. Test each bottle's spray before campers start since clogged nozzles frustrate fast. For g1012, add taped-down stencil shapes or masking-tape line designs they peel off at the end to reveal sharp negative space.","safety":"Never let campers spray paint toward another person's face or eyes; set a firm rule that bottles aim only at the paper on the wall, and rinse hands after since thinned paint runs everywhere.","ages":["g46","g79","g1012"],"rating":0,"links":[{"label":"Little Bins for Little Hands: summer camp art activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Lay leaves or paper shapes on the page, spray over them, then lift for crisp silhouettes.","Run a team relay where each camper adds one color spray before passing the bottle.","Use just one color on white paper for a moody monochrome spray gradient.","For g1012, tape a multi-layer masking-tape design onto the paper and remove layers between spray rounds for a stenciled poster effect."],"subsets":[["Pick a wall you can hose down after"],["Thin enough to spray without clogging","Test-spray off to the side first"],[],[],["Close = bold spots, far = fine mist"],[]]},
  {"id":"fp-salt-raised-painting","title":"Salt-Raised Painting","altNames":["Salt Painting","Glue and Salt Art","Raised Salt Watercolor"],"type":"Craft","place":"Inside","ageMin":9,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Trace glue lines, coat them in salt, then watch paint creep along the raised ridges like magic.","materials":["White glue in squeeze bottles, 1 per pair","Table salt, 1 cup per table","Paint thinned with water, in cups","Paintbrushes, 1 per camper","Cardstock or thick assorted paper, 1 per camper","Tray to catch loose salt","Paper towels"],"materialTags":["Glue","Paint","Paintbrushes","Paper","Paper towels"],"steps":["Squeeze glue onto cardstock to draw a simple design like a star, web, or initial.","Sprinkle table salt generously over all the wet glue lines.","Tip the paper over a tray to shake off the loose salt, leaving salt stuck along the glue.","Load a brush with watery paint and gently touch it to the salty ridges.","Watch the paint wick and spread along the salt lines, adding more colors at different points.","Let it dry undisturbed so the raised, crystallized lines stay intact."],"notes":"Use thick cardstock; thin paper buckles under all the wet glue and salt. The wicking effect is the wow moment, so let campers just touch the brush and watch rather than scrubbing. For g79, have them design interconnected line networks so they can predict how paint will travel from junction to junction.","safety":"Loose salt scattered on the floor is a slip hazard and irritates eyes if rubbed in; keep a catch tray under the shaking step and have campers wash hands before touching their faces.","ages":["g46","g79"],"rating":0,"media":[{"title":"Raised Salt Painting for Kids — glue, salt, and watercolor STEAM art (video tutorial)","url":"https://www.youtube.com/watch?v=pHmujSn8w9g"}],"links":[{"label":"Little Bins for Little Hands: summer camp art activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Do it on dark cardstock with bright paint for a glowing constellation look.","Spell out a name or word in glue and salt for a textured nameplate.","Use only cool or only warm colors for a themed wicking effect.","For g1012, challenge campers to map a real diagram (river system, circuit, constellation lines) so the wicking paint flows along an accurate design."],"subsets":[["Thick continuous glue lines wick best"],["Cover every glue line completely"],["Shake over a tray to save salt","Tap gently so the stuck salt stays"],["Touch, do not scrub, the salt"],[],[]]},
  {"id":"fp-dot-painting","title":"Dot Painting Mandalas","altNames":["Dot Mandala Art","Pointillism Dots","Q-Tip Dot Painting"],"type":"Craft","place":"Inside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Build a hypnotic mandala one tiny paint dot at a time using cotton swabs and brush ends.","materials":["Paint in small wells or paper plates","Cotton swabs, pencil erasers, or straw ends as dotters","Cardstock or dark assorted paper, 1 per camper","A coin or cup to trace a center circle","Paper towels","Markers for the guide circle"],"materialTags":["Paint","Paper","Straws","Markers","Paper towels"],"steps":["Trace a light circle in the center of the paper as a starting guide.","Dip a cotton swab or brush end in paint and press a single dot at the center.","Make a ring of evenly spaced dots around the center, keeping the spacing consistent.","Add more rings outward, changing color and dot size as you go to build a mandala.","Use the very tip of a straw for tiny accent dots between the big ones.","Let it dry flat so the raised dots keep their domed shape."],"notes":"Calm, focused, and surprisingly meditative; good as a cooldown after a high-energy block. The trick is even spacing, so encourage campers to rotate the paper rather than reaching across. For g79 and g1012, push symmetry rules (rotational, 8-fold) and graduated dot sizes for genuinely striking results.","safety":"Cotton swabs and straws can poke if waved around; remind campers to keep dotters pointed at the paper, and seat them with enough elbow room so no one jabs a neighbor.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Easy Beginner Dot Mandala Tutorial — how to paint a dot mandala (video tutorial)","url":"https://www.youtube.com/watch?v=OV9ZxcEIgj4"}],"links":[{"label":"Little Bins for Little Hands: summer camp art activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Dot-paint a simple animal or flower outline drawn in marker first.","Use only two alternating colors for a clean two-tone mandala.","Make dot-painted bookmarks on cardstock strips.","For g1012, require true rotational symmetry where every ring repeats a fixed pattern measured by spacing, not just eyeballed."],"subsets":[["Light guide circle, you can paint over it"],[],["Rotate the paper instead of reaching across","Keep gaps even"],["Big dots for bold rings, small for detail"],[],[]]},
  {"id":"fp-foam-sheet-stencils","title":"Foam Sheet Stencil Prints","altNames":["Foam Stencils","Foam Cutout Painting","Stencil Spray Art"],"type":"Craft","place":"Inside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Cut a reusable shape out of a foam sheet, then sponge paint through it to print crisp silhouettes.","materials":["Foam sheets, 1 per camper","Scissors","Paint in shallow trays","Sponges, 1 per camper","Assorted paper, 2 sheets per camper","Masking tape","Markers for drawing the stencil","Paper towels"],"materialTags":["Foam sheets","Scissors","Paint","Sponges","Paper","Masking tape","Markers","Paper towels"],"steps":["Draw a bold shape (star, leaf, lightning bolt) on a foam sheet with marker.","Cut the shape out of the middle of the foam so the sheet becomes a window stencil.","Tape the foam stencil flat onto a sheet of paper.","Dab a sponge into paint, blot off the excess, and pounce it over the open stencil window.","Lift the stencil straight up to reveal a crisp painted silhouette.","Reuse the same stencil to repeat the shape in a pattern or in different colors."],"notes":"Cutting the inside window neatly is the hard part, so let campers fold the foam to start an interior cut. Pouncing the sponge straight down keeps edges sharp; dragging it smears under the stencil. For g79 and g1012, have them cut layered multi-stencil designs that build a multi-color image in registered passes.","safety":"Starting an interior cut means poking scissors into the middle of the foam, which is where slips happen; have campers fold the foam to snip a starter slit rather than stabbing the point through.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Making stamps and stencils from kids' craft foam — video tutorial","url":"https://www.youtube.com/watch?v=eVzc398Vc-w"}],"links":[{"label":"S&S Blog: summer camp themes and activity ideas","url":"https://www.ssww.com/blog/top-10-summer-camp-themes-creative-engaging-activity-ideas/"}],"variations":["Cut a superhero emblem stencil and spray-print it onto a paper mask or cape.","Make an initial or number stencil for a personalized sign.","Stencil a repeating border around the edge of a poster.","For g1012, design a two-layer stencil where a second registered cutout adds detail color over the first silhouette."],"subsets":[["Keep the shape bold with no thin necks"],["Fold the foam to start the inner cut","Cut toward the marker line, not your hand"],[],["Blot the sponge so it is nearly dry","Pounce straight down, never drag"],[],[]]},
  {"id":"fp-painted-story-stones","title":"Painted Story Stones","altNames":["Story Stones","Painted Rocks","Rock Story Prompts"],"type":"Craft","place":"Both","ageMin":6,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Paint smooth stones with simple icons that become prompts for a story-circle storytelling game.","materials":["Smooth flat stones, 3-5 per camper","Paint","Paintbrushes, 1 per camper","Markers for fine details","Paper plates as palettes","Paper towels","A bag or cup to collect finished stones"],"materialTags":["Paint","Paintbrushes","Markers","Paper towels"],"steps":["Choose smooth stones and wipe them clean and dry so paint sticks.","Paint a base color over each stone if desired and let it set briefly.","Paint one simple icon per stone, like a star, animal, tree, sun, or wave.","Add fine outlines and details with marker once the paint is dry to the touch.","Let all stones fully dry, then pool everyone's stones into a shared bag.","Play by drawing a few stones and weaving their icons into a made-up story together."],"notes":"Collect smooth stones ahead of time or have campers hunt for them on a short nature walk to open the session. Keep icons simple and bold so they read as story prompts. For g79, run the storytelling as a structured round-robin where each player must continue the previous camper's tale using their drawn stones.","safety":"Stones are throwable and hard; set a clear no-throwing rule and keep painted stones on the table, since dropped stones can hurt feet or chip a tooth if mishandled.","ages":["g13","g46","g79"],"rating":0,"links":[{"label":"How to Make Story Stones for Kids — illustrated step-by-step guide","url":"https://artfulparent.com/story-stones-ideas-storytelling-rocks/"},{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Paint a matching set of pairs and use the stones as a memory-match game.","Make kindness stones with a single uplifting word to leave around camp.","Paint tic-tac-toe X and O stones for a reusable outdoor game set.","For g1012, assign genre stones (twist, setting, character) and run a structured story-building challenge with a time limit per turn."],"subsets":[["Clean and fully dry, or paint flakes off"],[],["One clear icon per stone reads best"],["Wait until paint is dry before marker details"],[],["Draw a few at random","Build on the last person's story"]]},
  {"id":"fp-galaxy-splatter-art","title":"Galaxy Splatter Art","altNames":["Galaxy Painting","Nebula Splatter Art","Space Sky Art"],"type":"Craft","place":"Inside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":2,"prep":"Medium","blurb":"Blend deep-space color clouds, then flick a spray of white star-speckles across your own galaxy.","materials":["Black or dark assorted paper, 1 per camper","Paint in purples, blues, pinks, and white","Sponges, 1 per camper","Paintbrushes for splattering, 1 per camper","Paper plates as palettes","Masking tape","Paper towels"],"materialTags":["Paper","Paint","Sponges","Paintbrushes","Masking tape","Paper towels"],"steps":["Tape a sheet of dark paper flat to the table.","Sponge soft cloudy patches of purple and blue across the page, overlapping the edges.","Add pink and lighter blue clouds on top while the paint is still wet so colors blend.","Dab a few brighter white-blue centers to glow like distant nebulae.","Load a brush with white paint and flick it over the whole page to splatter a field of tiny stars.","Add a handful of larger white dots as bright stars and let the galaxy dry flat."],"notes":"Build the color clouds dark-to-light and keep them blended while wet for that smoky nebula look. The star splatter is the finishing magic, so save it for last and keep it fine. For g1012, introduce real nebula reference photos and challenge them to match a specific color palette and star density.","safety":"The white star-flicking sends paint flecks beyond the page; have campers face the same way with spacing between them, and protect clothing with smocks since white paint shows on dark shirts.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Galaxy nebula sponge painting with acrylics — quick & easy video demo","url":"https://www.youtube.com/watch?v=jLrEK9m4f_4"}],"links":[{"label":"Little Bins for Little Hands: summer camp art activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Add a taped-off planet circle that stays dark, then peel the tape for a clean planet silhouette.","Cut the dried galaxy into bookmark strips so everyone gets several keepsakes.","Make a galaxy jar lid or paper-cup lantern by wrapping the painted paper around a cup.","For g1012, recreate a named nebula from a reference image, matching its real colors and the density of its star field."],"subsets":[[],["Dab, do not scrub, so clouds stay soft","Overlap edges for a smoky look"],["Blend while wet for smooth transitions"],[],["Flick lightly for fine stars","Keep the spray over your own page"],[]]},
  {"id":"fp-symmetry-blot-art","title":"Symmetry Blot Art","altNames":["Rorschach Blot Art","Fold and Print Painting","Mirror Paint Blots"],"type":"Craft","place":"Inside","ageMin":6,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Drop paint on one half, fold, press, and unfold to reveal a perfectly mirrored butterfly or monster.","materials":["Assorted paper, 1-2 sheets per camper","Paint in cups or wells","Spoons or brushes for dropping paint","Markers for details","Scissors (optional, to cut out shapes)","Paper towels"],"materialTags":["Paper","Paint","Paintbrushes","Markers","Scissors","Paper towels"],"steps":["Fold a sheet of paper in half and crease it, then open it flat again.","Spoon or brush blobs of paint onto only one side of the fold line.","Fold the clean half back over onto the painted half and press and smooth from the center outward.","Open the paper to reveal the mirrored blot pattern.","Decide what the symmetric shape looks like, then add marker details to bring it to life.","Let it dry flat; optionally cut around the shape to make a standalone figure."],"notes":"Fast, satisfying, and impossible to mess up, which makes it a great filler or rainy-block backup. Use a moderate amount of paint; too much oozes out the edges. For g79 and g1012, turn it into a real symmetry lesson, predicting and labeling the mirror line, then layering blots for complex bilateral creatures.","safety":"Excess paint squeezes out the fold and can flick when pressed; press gently from the center so it does not squirt, and keep the paper flat on the table while pressing.","ages":["g13","g46","g79","g1012"],"rating":0,"links":[{"label":"How to Paint Blot Symmetrical Butterfly Paintings — step-by-step tutorial","url":"https://handsonaswegrow.com/paint-blot-symmetrical-butterfly-painting/"},{"label":"Little Bins for Little Hands: summer camp art activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Place blobs in a butterfly-body line so the unfolded print becomes wings.","Use a limited two-color palette so the mirrored blend stays clean.","Cut out the dried symmetric shape and string several into a mobile.","For g1012, fold on two axes (quarter-fold) to create four-way radial symmetry and have them map where each blob lands."],"subsets":[["Crease firmly so the mirror line is sharp"],["Paint only one side of the fold","Moderate amount, it spreads when pressed"],["Press from the center outward","Smooth with a flat hand"],[],[],[]]},
];
